def render_lesson(lesson_id: int) -> bool:
    lesson = LESSONS.get(lesson_id)
    if not lesson:
        st.error(f"Lesson 2.{lesson_id} not found.")
        return False

    already_done = is_lesson_complete(TRACK_ID, lesson_id)

    # Handle diagram sentinels and embedded img tags in concept
    concept = lesson["concept"]

    def render_concept_part(text):
        # Render the whole segment as a single st.markdown call. Previously
        # this split out inline <img>/<div> elements into separate calls so
        # their HTML would pass through unsafe_allow_html. That worked for
        # rendering, but it produced three stacked Streamlit element
        # containers (text-above, image, text-below), each with its own
        # default vertical spacing — which is the source of the unshrinkable
        # gap around inline images. Rendering as one block keeps all the
        # content inside a single element container, so the image sits flush
        # against surrounding text with only the image's own margin driving
        # the spacing.
        if not text.strip():
            return
        if "<img " in text or "<iframe " in text or "<div " in text:
            st.markdown(text, unsafe_allow_html=True)
        else:
            st.markdown(text)

    # Sentinel tokens that embed a full HTML diagram inline at the sentinel's
    # location. Adding a new diagram only requires registering it in
    # components.diagrams and mapping its sentinel here.
    _diagram_sentinels = {
        "[[MODEL_COMPARISON_DIAGRAM]]": "model_comparison",
        "[[PHI_DECISION_DIAGRAM]]": "phi_decision",
    }
    _active_sentinel = next((s for s in _diagram_sentinels if s in concept), None)
    if _active_sentinel:
        import streamlit.components.v1 as components
        from components.diagrams import get_diagram, get_diagram_height
        diagram_id = _diagram_sentinels[_active_sentinel]
        parts = concept.split(_active_sentinel)
        for i, part in enumerate(parts):
            if part.strip():
                render_concept_part(part)
            if i < len(parts) - 1:
                html = get_diagram(diagram_id)
                height = get_diagram_height(diagram_id)
                if html:
                    components.html(html, height=height, scrolling=False)
    else:
        render_concept_part(concept)
    st.markdown("---")

    if already_done:
        if not lesson.get("challenge"):
            st.success("✓  Lesson complete")
            return True

    # Lessons with quiz only (no challenge)
    if lesson.get("quiz") and not lesson.get("challenge"):
        return render_quiz(
            track_id=TRACK_ID,
            lesson_id=lesson_id,
            questions=lesson["quiz"],
            label="Knowledge check",
        )

    # Lesson 2.4: quiz followed by graded challenge
    if lesson.get("quiz") and lesson.get("challenge"):
        quiz_passed = render_quiz(
            track_id=TRACK_ID,
            lesson_id=lesson_id,
            questions=lesson["quiz"],
            label="Knowledge check",
            mark_complete=False,
        )

        if not quiz_passed:
            return False

        ch = lesson["challenge"]
        return render_graded_challenge(
            track_id=TRACK_ID,
            lesson_id=lesson_id,
            scenario=ch["scenario"],
            broken_example=ch["broken_example"],
            rubric=ch["rubric"],
            model_answer=ch["model_answer"],
            hints=ch["hints"],
            input_label="Your verification prompt",
            max_chars=1000,
        )

    st.info("Content coming soon.", icon="🔜")
    return False
